// Rule 1: Different element types -> destroy old, create new
// <div><Counter /></div>  →  <span><Counter /></span>
// Counter component is unmounted and remounted

// Rule 2: Same element type -> update attributes
// <div className="old" />  →  <div className="new" />
// Only className is updated, DOM node is reused

// Rule 3: Same component type -> update props
// <Counter count={1} />  →  <Counter count={2} />
// Same instance, componentDidUpdate / useEffect runs

// Rule 4: Keys identify children across renders
// <li key="a">A</li>    →  <li key="b">B</li>
// <li key="b">B</li>        <li key="a">A</li>
// React knows A and B just swapped positions

import { useState, useMemo, useCallback } from 'react';

function ProductList({ products, tax }) {
  // useMemo: memoize a COMPUTED VALUE
  const total = useMemo(() => {
    console.log('Computing total...');
    return products.reduce((sum, p) => sum + p.price, 0) * (1 + tax);
  }, [products, tax]);

  // useCallback: memoize a FUNCTION REFERENCE
  const handleSort = useCallback((field) => {
    console.log('Sorting by', field);
    // sort logic here
  }, []); // empty deps = stable reference

  return (
    <div>
      <p>Total: ${total.toFixed(2)}</p>
      <SortButton onSort={handleSort} />
    </div>
  );
}

// useCallback matters when passing to memoized children
const SortButton = React.memo(({ onSort }) => {
  console.log('SortButton rendered');
  return <button onClick={() => onSort('price')}>Sort</button>;
});

import { useState, useEffect } from 'react';

function useWindowSize() {
  const [size, setSize] = useState({
    width: window.innerWidth,
    height: window.innerHeight,
  });

  useEffect(() => {
    const handleResize = () => {
      setSize({
        width: window.innerWidth,
        height: window.innerHeight,
      });
    };

    window.addEventListener('resize', handleResize);

    // Cleanup function - runs on unmount
    // and before each re-run of the effect
    return () => {
      window.removeEventListener('resize', handleResize);
    };
  }, []); // empty deps = only run once

  return size;
}

function Timer() {
  const [count, setCount] = useState(0);

  // BUG: count is always 0 in the callback
  useEffect(() => {
    const id = setInterval(() => {
      console.log(count); // always 0!
      setCount(count + 1); // always sets to 1
    }, 1000);
    return () => clearInterval(id);
  }, []); // empty deps = stale closure

  // FIX: use functional update
  useEffect(() => {
    const id = setInterval(() => {
      setCount(prev => prev + 1); // always correct
    }, 1000);
    return () => clearInterval(id);
  }, []);

  return <p>Count: {count}</p>;
}

