function BatchingExample() {
  const [count, setCount] = useState(0);
  const [flag, setFlag] = useState(false);
  console.log('Rendered!'); // How many times?

  // React 18: ALL updates are batched (one re-render)
  function handleClick() {
    setCount(c => c + 1);
    setFlag(f => !f);
    // Only ONE re-render happens here
  }

  // Even in async code - React 18 batches these too!
  async function handleAsync() {
    const data = await fetch('/api/data');
    setCount(c => c + 1);
    setFlag(f => !f);
    // Still only ONE re-render in React 18
    // In React 17, this would cause TWO re-renders
  }

  // To opt OUT of batching (rare):
  import { flushSync } from 'react-dom';
  function handleUrgent() {
    flushSync(() => setCount(c => c + 1));
    // DOM is updated here
    flushSync(() => setFlag(f => !f));
    // DOM is updated here
  }

  return <button onClick={handleClick}>{count}</button>;
}

function Counter() {
  const [count, setCount] = useState(0);

  // BUG: All three use the SAME stale value of count
  function handleBrokenTripleIncrement() {
    setCount(count + 1); // 0 + 1 = 1
    setCount(count + 1); // 0 + 1 = 1 (count is still 0!)
    setCount(count + 1); // 0 + 1 = 1
    // Result: count = 1, NOT 3
  }

  // CORRECT: Each update uses the latest pending state
  function handleTripleIncrement() {
    setCount(prev => prev + 1); // 0 + 1 = 1
    setCount(prev => prev + 1); // 1 + 1 = 2
    setCount(prev => prev + 1); // 2 + 1 = 3
    // Result: count = 3
  }

  return (
    <div>
      <p>Count: {count}</p>
      <button onClick={handleTripleIncrement}>+3</button>
    </div>
  );
}

function TodoApp() {
  const [todos, setTodos] = useState([
    { id: 1, text: 'Learn React', done: false },
    { id: 2, text: 'Build project', done: false },
  ]);

  // BAD: Mutating state directly
  function brokenToggle(id) {
    const todo = todos.find(t => t.id === id);
    todo.done = !todo.done; // Mutation!
    setTodos(todos); // Same reference - React won't re-render!
  }

  // GOOD: Create new array with new object
  function toggle(id) {
    setTodos(prev => prev.map(todo =>
      todo.id === id
        ? { ...todo, done: !todo.done }
        : todo
    ));
  }

  // Add item (new array with new item)
  function addTodo(text) {
    setTodos(prev => [
      ...prev,
      { id: Date.now(), text, done: false }
    ]);
  }

  // Remove item (filter creates new array)
  function removeTodo(id) {
    setTodos(prev => prev.filter(t => t.id !== id));
  }

  return (
    <ul>
      {todos.map(todo => (
        <li key={todo.id} onClick={() => toggle(todo.id)}>
          {todo.done ? '✓' : '○'} {todo.text}
        </li>
      ))}
    </ul>
  );
}

function UserProfile({ userId }) {
  const [user, setUser] = useState(null);

  // BUG: Race condition
  // If userId changes quickly, a slow request for user 1
  // can overwrite the result for user 2
  useEffect(() => {
    fetch(`/api/users/${userId}`)
      .then(res => res.json())
      .then(data => setUser(data));
  }, [userId]);

  // FIX 1: Boolean flag
  useEffect(() => {
    let cancelled = false;
    fetch(`/api/users/${userId}`)
      .then(res => res.json())
      .then(data => {
        if (!cancelled) setUser(data);
      });
    return () => { cancelled = true; };
  }, [userId]);

  // FIX 2: AbortController (preferred)
  useEffect(() => {
    const controller = new AbortController();
    fetch(`/api/users/${userId}`, {
      signal: controller.signal
    })
      .then(res => res.json())
      .then(data => setUser(data))
      .catch(err => {
        if (err.name !== 'AbortError') throw err;
      });
    return () => controller.abort();
  }, [userId]);

  return user ? <h1>{user.name}</h1> : <p>Loading...</p>;
}

function SearchResults({ query }) {
  const [results, setResults] = useState([]);

  // INFINITE LOOP: options object is recreated every render
  const options = { limit: 10, sort: 'date' };
  useEffect(() => {
    fetchResults(query, options).then(setResults);
  }, [query, options]); // options is new every render!

  // FIX 1: Move object inside useEffect
  useEffect(() => {
    const options = { limit: 10, sort: 'date' };
    fetchResults(query, options).then(setResults);
  }, [query]);

  // FIX 2: useMemo for dynamic values
  const options = useMemo(
    () => ({ limit: 10, sort: sortField }),
    [sortField]
  );
  useEffect(() => {
    fetchResults(query, options).then(setResults);
  }, [query, options]);

  // FIX 3: Depend on primitives, not objects
  useEffect(() => {
    fetchResults(query, { limit: 10, sort: sortField })
      .then(setResults);
  }, [query, sortField]); // primitives are stable
}

import { useEffect, useLayoutEffect, useRef, useState } from 'react';

function Tooltip({ targetRef, text }) {
  const tooltipRef = useRef(null);
  const [position, setPosition] = useState({ top: 0, left: 0 });

  // useEffect: runs AFTER paint (async)
  // Can cause visible flicker if positioning elements
  useEffect(() => {
    const rect = targetRef.current.getBoundingClientRect();
    setPosition({ top: rect.bottom + 8, left: rect.left });
  }, [targetRef]);

  // useLayoutEffect: runs BEFORE paint (sync)
  // Blocks paint until complete - no flicker
  useLayoutEffect(() => {
    const rect = targetRef.current.getBoundingClientRect();
    setPosition({ top: rect.bottom + 8, left: rect.left });
  }, [targetRef]);

  return (
    <div
      ref={tooltipRef}
      style={{ position: 'fixed', top: position.top, left: position.left }}
    >
      {text}
    </div>
  );
}

// Rule of thumb:
// useEffect       -> data fetching, subscriptions, logging
// useLayoutEffect -> DOM measurements, synchronous visual updates

import { useRef, useState, useEffect } from 'react';

function SearchInput() {
  const inputRef = useRef(null);
  const renderCount = useRef(0);
  const prevQuery = useRef('');
  const [query, setQuery] = useState('');

  // Track render count without causing re-renders
  renderCount.current += 1;

  // Store previous value
  useEffect(() => {
    prevQuery.current = query;
  }, [query]);

  // Focus input on mount
  useEffect(() => {
    inputRef.current.focus();
  }, []);

  return (
    <div>
      <input
        ref={inputRef}
        value={query}
        onChange={(e) => setQuery(e.target.value)}
        placeholder="Search..."
      />
      <p>Current: {query}</p>
      <p>Previous: {prevQuery.current}</p>
      <p>Renders: {renderCount.current}</p>
    </div>
  );
}

