// Parent can now access the input DOM element
function LoginForm() {
  const emailRef = useRef(null);
  const passwordRef = useRef(null);

  function handleSubmit(e) {
    e.preventDefault();
    if (!emailRef.current.value) {
      emailRef.current.focus();
      return;
    }
  }

  return (
    <form onSubmit={handleSubmit}>
      <FancyInput ref={emailRef} label="Email" type="email" />
      <FancyInput ref={passwordRef} label="Password" type="password" />
      <button type="submit">Login</button>
    </form>
  );
}

import { forwardRef, useRef, useImperativeHandle, useState } from 'react';

const VideoPlayer = forwardRef(function VideoPlayer({ src }, ref) {
  const videoRef = useRef(null);
  const [isPlaying, setIsPlaying] = useState(false);

  // Expose a limited API instead of the full DOM node
  useImperativeHandle(ref, () => ({
    play() {
      videoRef.current.play();
      setIsPlaying(true);
    },
    pause() {
      videoRef.current.pause();
      setIsPlaying(false);
    },
    restart() {
      videoRef.current.currentTime = 0;
      videoRef.current.play();
      setIsPlaying(true);
    },
    get isPlaying() {
      return isPlaying;
    }
  }), [isPlaying]);

  return <video ref={videoRef} src={src} />;
});

// Parent uses the custom API
function App() {
  const playerRef = useRef(null);
  return (
    <div>
      <VideoPlayer ref={playerRef} src="/video.mp4" />
      <button onClick={() => playerRef.current.play()}>Play</button>
      <button onClick={() => playerRef.current.pause()}>Pause</button>
      <button onClick={() => playerRef.current.restart()}>Restart</button>
    </div>
  );
}

// With useState - scattered logic, easy to forget updates
function ShoppingCart() {
  const [items, setItems] = useState([]);
  const [total, setTotal] = useState(0);
  const [itemCount, setItemCount] = useState(0);
  const [discount, setDiscount] = useState(0);

  // Must remember to update ALL related values
  function addItem(product) {
    setItems(prev => [...prev, product]);
    setTotal(prev => prev + product.price);
    setItemCount(prev => prev + 1);
    // Forgot to update discount? Bug!
    if (itemCount + 1 >= 5) {
      setDiscount(0.1);
    }
  }

  function removeItem(id) {
    const item = items.find(i => i.id === id);
    setItems(prev => prev.filter(i => i.id !== id));
    setTotal(prev => prev - item.price);
    setItemCount(prev => prev - 1);
    // Same scattered update logic...
  }

  return <div>{/* UI */}</div>;
}

const initialState = {
  items: [],
  total: 0,
  itemCount: 0,
  discount: 0,
};

function cartReducer(state, action) {
  switch (action.type) {
    case 'ADD_ITEM': {
      const newItems = [...state.items, action.payload];
      const newCount = state.itemCount + 1;
      return {
        items: newItems,
        total: state.total + action.payload.price,
        itemCount: newCount,
        discount: newCount >= 5 ? 0.1 : state.discount,
      };
    }
    case 'REMOVE_ITEM': {
      const item = state.items.find(i => i.id === action.payload);
      const newCount = state.itemCount - 1;
      return {
        items: state.items.filter(i => i.id !== action.payload),
        total: state.total - item.price,
        itemCount: newCount,
        discount: newCount < 5 ? 0 : state.discount,
      };
    }
    case 'CLEAR_CART':
      return initialState;
    default:
      return state;
  }
}

function ShoppingCart() {
  const [state, dispatch] = useReducer(cartReducer, initialState);

  return (
    <div>
      <p>Items: {state.itemCount} | Total: ${state.total}</p>
      <button onClick={() => dispatch({
        type: 'ADD_ITEM',
        payload: { id: 1, name: 'Shirt', price: 29.99 }
      })}>Add Shirt</button>
      <button onClick={() => dispatch({ type: 'CLEAR_CART' })}>
        Clear Cart
      </button>
    </div>
  );
}

const CartContext = createContext(null);
const CartDispatchContext = createContext(null);

// Provider wraps the app
function CartProvider({ children }) {
  const [state, dispatch] = useReducer(cartReducer, initialState);
  return (
    <CartContext.Provider value={state}>
      <CartDispatchContext.Provider value={dispatch}>
        {children}
      </CartDispatchContext.Provider>
    </CartContext.Provider>
  );
}

// Custom hooks for clean access
function useCart() {
  return useContext(CartContext);
}
