function RegistrationForm() {
  const [form, setForm] = useState({
    name: '', email: '', password: ''
  });
  const [errors, setErrors] = useState({});
  const [touched, setTouched] = useState({});

  function validate(values) {
    const errs = {};
    if (!values.name.trim()) errs.name = 'Name is required';
    if (!values.email.includes('@')) errs.email = 'Valid email required';
    if (values.password.length < 8) errs.password = 'Min 8 characters';
    return errs;
  }

  function handleChange(e) {
    const { name, value } = e.target;
    setForm(prev => ({ ...prev, [name]: value }));
    // Clear error on change
    if (errors[name]) {
      setErrors(prev => ({ ...prev, [name]: null }));
    }
  }

  function handleBlur(e) {
    const { name } = e.target;
    setTouched(prev => ({ ...prev, [name]: true }));
    const errs = validate(form);
    setErrors(errs);
  }

  function handleSubmit(e) {
    e.preventDefault();
    const errs = validate(form);
    setErrors(errs);
    setTouched({ name: true, email: true, password: true });
    if (Object.keys(errs).length === 0) {
      console.log('Submitting:', form);
    }
  }

  return (
    <form onSubmit={handleSubmit}>
      <div>
        <input name="name" value={form.name}
          onChange={handleChange} onBlur={handleBlur} />
        {touched.name && errors.name && <span>{errors.name}</span>}
      </div>
      <div>
        <input name="email" value={form.email}
          onChange={handleChange} onBlur={handleBlur} />
        {touched.email && errors.email && <span>{errors.email}</span>}
      </div>
      <div>
        <input name="password" type="password" value={form.password}
          onChange={handleChange} onBlur={handleBlur} />
        {touched.password && errors.password && <span>{errors.password}</span>}
      </div>
      <button type="submit">Register</button>
    </form>
  );
}

import { useForm } from 'react-hook-form';
import { zodResolver } from '@hookform/resolvers/zod';
import { z } from 'zod';

// Schema can be shared with server-side validation
const schema = z.object({
  name: z.string().min(1, 'Name is required'),
  email: z.string().email('Invalid email'),
  password: z.string().min(8, 'Min 8 characters'),
  confirmPassword: z.string(),
}).refine(data => data.password === data.confirmPassword, {
  message: 'Passwords must match',
  path: ['confirmPassword'],
});

function RegistrationForm() {
  const {
    register,
    handleSubmit,
    formState: { errors, isSubmitting }
  } = useForm({
    resolver: zodResolver(schema),
    mode: 'onBlur',
  });

  async function onSubmit(data) {
    await fetch('/api/register', {
      method: 'POST',
      body: JSON.stringify(data),
    });
  }

  return (
    <form onSubmit={handleSubmit(onSubmit)}>
      <input {...register('name')} />
      {errors.name && <span>{errors.name.message}</span>}

      <input {...register('email')} />
      {errors.email && <span>{errors.email.message}</span>}

      <input type="password" {...register('password')} />
      {errors.password && <span>{errors.password.message}</span>}

      <input type="password" {...register('confirmPassword')} />
      {errors.confirmPassword && <span>{errors.confirmPassword.message}</span>}

      <button disabled={isSubmitting}>Register</button>
    </form>
  );
}

function useForm(initialValues, validate) {
  const [values, setValues] = useState(initialValues);
  const [errors, setErrors] = useState({});
  const [touched, setTouched] = useState({});
  const [isSubmitting, setIsSubmitting] = useState(false);

  function handleChange(e) {
    const { name, value, type, checked } = e.target;
    setValues(prev => ({
      ...prev,
      [name]: type === 'checkbox' ? checked : value
    }));
  }

  function handleBlur(e) {
    const { name } = e.target;
    setTouched(prev => ({ ...prev, [name]: true }));
    if (validate) setErrors(validate(values));
  }

  async function handleSubmit(onSubmit) {
    return async (e) => {
      e.preventDefault();
      const errs = validate ? validate(values) : {};
      setErrors(errs);
      const allTouched = Object.keys(values).reduce(
        (acc, key) => ({ ...acc, [key]: true }), {}
      );
      setTouched(allTouched);
      if (Object.keys(errs).length === 0) {
        setIsSubmitting(true);
        await onSubmit(values);
        setIsSubmitting(false);
      }
    };
  }

  return {
    values, errors, touched, isSubmitting,
    handleChange, handleBlur, handleSubmit,
  };
}

