function AsyncExample() {
  useEffect(() => {
    // Error Boundaries do NOT catch async errors
    async function fetchData() {
      try {
        const res = await fetch('/api/data');
        if (!res.ok) throw new Error('Failed to fetch');
        return res.json();
      } catch (error) {
        // Handle async error with state
        setError(error);
      }
    }
    fetchData();
  }, []);
}

