// Dynamic route: /users/:userId
function UserProfile() {
  const { userId } = useParams();
  const navigate = useNavigate();
  const [user, setUser] = useState(null);

  useEffect(() => {
    fetch(`/api/users/${userId}`)
      .then(res => {
        if (!res.ok) throw new Error('Not found');
        return res.json();
      })
      .then(setUser)
      .catch(() => navigate('/404', { replace: true }));
  }, [userId, navigate]);

  if (!user) return <Spinner />;
  return <div><h1>{user.name}</h1></div>;
}

// Search params for filters: /products?category=shoes&sort=price
function ProductList() {
  const [searchParams, setSearchParams] = useSearchParams();
  const category = searchParams.get('category') || 'all';
  const sort = searchParams.get('sort') || 'name';
  const page = parseInt(searchParams.get('page') || '1');

  function updateFilters(updates) {
    setSearchParams(prev => {
      const next = new URLSearchParams(prev);
      Object.entries(updates).forEach(([key, value]) => {
        if (value) next.set(key, value);
        else next.delete(key);
      });
      return next;
    });
  }

  return (
    <div>
      <select value={category}
        onChange={e => updateFilters({ category: e.target.value })}>
        <option value="all">All</option>
        <option value="shoes">Shoes</option>
      </select>
      <button onClick={() => updateFilters({ page: String(page + 1) })}>
        Next Page
      </button>
    </div>
  );
}

// HOC that adds authentication
function withAuth(WrappedComponent) {
  return function AuthenticatedComponent(props) {
    const { user, isAuthenticated } = useAuth();

    if (!isAuthenticated) {
      return <Navigate to="/login" />;
    }

    // Pass user data + original props to wrapped component
    return <WrappedComponent {...props} user={user} />;
  };
}

// HOC that adds loading state
function withLoading(WrappedComponent) {
  return function LoadingComponent({ isLoading, ...props }) {
    if (isLoading) return <Spinner />;
    return <WrappedComponent {...props} />;
  };
}

